// ---------- String:


ns bit {
    // create a bit-vector, initialized with the value of 'str', and with the number of bytes needed to store 'str', plus 1.
    //   used to initialize a string, like:   bit.str "Hello, World!\n"
    def str str {
        .vec (((#str)+15)>>3)<<3, str
    }
}



// ---------- Casting to ascii:


ns bit {
    // Complexity 9@-7
    //   ascii := the ascii representation of the value of bin.
    // ascii is bit[:8], bin is a bit.
    def bin2ascii ascii, bin {
        .zero 8, ascii
        .not 2, ascii + 4*dw   // ascii = 0x30
        .xor ascii, bin
    }


    // Complexity 12@-10
    //   ascii := the ascii representation of the value of dec.
    // ascii is bit[:8], dec is bit[:4].
    def dec2ascii ascii, dec {
        .zero 8, ascii
        .not 2, ascii + 4*dw   // ascii = 0x30
        .xor 4, ascii, dec
    }


    //  Time Complexity: 15@+7
    // Space Complexity: 21@+30
    //   ascii := the ascii representation of the value of hex (digits & capital-letters).
    // ascii is bit[:8], hex is bit[:4].
    def hex2ascii ascii, hex @ dec_label, hex_label, nine4, end {
        .zero 8, ascii
        .xor 3, ascii, hex
        .cmp 4, hex, nine4, dec_label, dec_label, hex_label
      dec_label:
        .xor ascii+3*dw, hex+3*dw
        .not 2, ascii + 4*dw    // ascii = 0x30
        ;end
      hex_label:
        .dec 3, ascii           // A-F is now 1-6
        .not ascii + 6*dw       // ascii = 0x40
        ;end
      nine4:
        .vec 4, 9
      end:
    }
}



// ---------- Casting from ascii:


ns bit {
    // Complexity: 17@+24
    //   if ascii is '0'/'1', set bit to 0/1 (end error=0).  else, set error=1.
    // ascii is bit[:8], and error(output-param),bin are bits.
    def ascii2bin error, bin, ascii @ half_bin, return_error, copy_binary_value, end {
        .zero error
        .zero bin

        .cmp 7, ascii+dw, half_bin, return_error, copy_binary_value, return_error

        return_error:
            .not error
            ;end

        copy_binary_value:
            .xor bin, ascii
            ;end

      half_bin:
        .vec 7, 0x30>>1

      end:
    }


    // Complexity: 25@+56
    //   if ascii is '0'-'9', set dec to that decimal digit value (end error=0).  else, set error=1.
    // ascii is bit[:8], dec in bit[:4], and error(output-param) is a bit.
    def ascii2dec error, dec, ascii @ half_dec, return_error, check_decimal, copy_decimal_value, nine4, end {
        .zero error
        .zero 4, dec

        .cmp 4, ascii+4*dw, half_dec, return_error, check_decimal, return_error
      check_decimal:
        .cmp 4, ascii, nine4, copy_decimal_value, copy_decimal_value, return_error

        return_error:
            .not error
            ;end

        copy_decimal_value:
            .xor 4, dec, ascii
            ;end

      half_dec:
        .vec 4, 0x30>>4
      nine4:
        .vec 4, 9
      end:
    }


    // Complexity: 53@+86
    //   if ascii is '0'-'9'/'a'-'f'/'A'-'F', set hex to that hexadecimal digit value (end error=0).  else, set error=1.
    // ascii is bit[:8], hex in bit[:4], and error(output-param) is a bit.
    def ascii2hex error, hex, ascii \
            @ decimal_ascii_msh, uppercase_hexadecimal_ascii_msh, lowercase_hexadecimal_ascii_msh, return_error, \
            check_uppercase_hex, check_lowercase_hex, dec_first_check, hex_first_check, hex_second_check, \
            copy_decimal_value, copy_hexadecimal_value, nine4, seven3, two3, end {
        .zero error
        .zero 4, hex

        .cmp 4, ascii+4*dw, decimal_ascii_msh, check_uppercase_hex, dec_first_check, check_uppercase_hex

      check_uppercase_hex:
        .cmp 5, ascii+3*dw, uppercase_hexadecimal_ascii_msh, check_lowercase_hex, hex_first_check, check_lowercase_hex
      check_lowercase_hex:
        .cmp 5, ascii+3*dw, lowercase_hexadecimal_ascii_msh, return_error,        hex_first_check, return_error

      dec_first_check:
        .cmp 4, ascii, nine4, copy_decimal_value, copy_decimal_value, return_error
      copy_decimal_value:
        .xor 4, hex, ascii
        ;end

      hex_first_check:
        .inc 3, ascii
        .cmp 3, ascii, two3,   return_error, hex_second_check, hex_second_check
      hex_second_check:
        .cmp 3, ascii, seven3, copy_hexadecimal_value, copy_hexadecimal_value, return_error
      copy_hexadecimal_value:
        .xor 3, hex, ascii
        .not hex+3*dw
        ;end

      return_error:
        .not error
        ;end

      decimal_ascii_msh:
        .vec 4, 0x30>>4
      uppercase_hexadecimal_ascii_msh:
        .vec 5, 0x40>>3
      lowercase_hexadecimal_ascii_msh:
        .vec 5, 0x60>>3
      nine4:
        .vec 4, 9
      seven3:
        .vec 3, 7
      two3:
        .vec 3, 2
      end:
    }
}

// ---------- Conditional Jumps


ns bit {
    // Complexity: @+2
    //   if x == 0 jump to l0, else jump to l1
    // x is a bit, l0,l1 are addresses.
    def if x, l0, l1 @ label_ptr, base_jump_label {
        .xor label_ptr, x
      label_ptr:
        ;base_jump_label
        pad 2
      base_jump_label:
        ;l0
        label_ptr + dbit;l1
    }

    // Complexity: n(@+2)
    //   if x[:n] == 0 jump to l0, else jump to l1
    // x is bit[:n], l0,l1 are addresses.
    def if n, x, l0, l1 {
        rep(n-1, i) .if1 x+i*dw, l1
        .if x+(n-1)*dw, l0, l1
    }

    // Complexity: @+2
    //   if x == 1 jump to l1
    // x is a bit, l1 is an address.
    def if1 x, l1 @ end {
        .if x, end, l1
      end:
    }

    // Complexity: n(@+2)
    //   if the x[:n] != 0 jump to l1
    // x is bit[:n], l1 is an address.
    def if1 n, x, l1 @ end {
        .if n, x, end, l1
      end:
    }

    // Complexity: @+2
    //   if x == 0 jump to l0
    // x is a bit, l0 is an address.
    def if0 x, l0 @ end {
        .if x, l0, end
      end:
    }

    // Complexity: n(@+2)
    //   if x[:n] == 0 jump to l0
    // x is bit[:n], l0 is an address.
    def if0 n, x, l0 @ end {
        .if n, x, l0, end
      end:
    }


    // Complexity: 2@+4
    // Space: 3@+6
    //   jump to:
    //     a < b:  lt
    //     a = b:  eq
    //     a > b:  gt
    // a,b are bits, lt,eq,gt are addresses.
    def cmp a, b, lt, eq, gt @ a_is1_label {
        .if1 a, a_is1_label
        .if b, eq, lt
      a_is1_label:
        .if b, gt, eq
    }

    //  TIme Complexity: n(2@+4)
    // Space Complexity: n(3@+6)
    //   jump to:
    //     a[:n] < b[:n]:  lt
    //     a[:n] = b[:n]:  eq
    //     a[:n] > b[:n]:  gt
    // a,b are bit[:n], lt,eq,gt are addresses.
    def cmp n, a, b, lt, eq, gt {
        rep(n-1, i) ._.cmp_next_eq a+(n-1-i)*dw, b+(n-1-i)*dw, lt, gt
        .cmp a, b, lt, eq, gt
    }
    ns _ {
        // Complexity: 2@+4
        // Space: 3@+6
        //   jump to:
        //     a < b:  lt
        //     a = b:  continue
        //     a > b:  gt
        // a,b are bits, lt,gt are addresses.
        def cmp_next_eq a, b, lt, gt @ eq {
            ..cmp a, b, lt, eq, gt
          eq:
        }
    }
}

ns bit {
    // Complexity: n(5@+11)
    //   dst[:n], src[:n] = src[:n] / 10, src[:n] % 10.
    def div10 n, dst, src @ zero, end {
        .zero n, dst
        .div10.cmp_sub_10 zero, src+(n-4)*dw, dst+(n-4)*dw
        rep(n-4, i) .div10.cmp_sub_10 src+(n-1-i)*dw, src+(n-5-i)*dw, dst+(n-5-i)*dw
        ;end
      zero: .bit 0  // this bit is never modified
      end:
    }
    ns div10 {
        // Complexity: 4@+12
        //   if (val > 10) {
        //     val -= 10;
        //     res  = !res;
        //   }
        // for val4:val[3,2,1,0] of length 5, and Assumes val <= 19.
        // This macro is getting called on consecutive 5-bits, shifting the 5-bit-frame 1 bit right at a time.
        def cmp_sub_10 val4, val, res @ yes, no, _1xxxx, _1xx0x, _1xx1x, _01x1x, _0110x {
            ..if1 val4, _1xxxx
            ..if0 val+3*dw, no
            ..if1 val+  dw, _01x1x
            ..if0 val+2*dw, no

          _0110x:
            ..not val+2*dw
            val+3*dw+dbit; yes

          _01x1x:
            val+3*dw+dbit; yes

          _1xxxx:
            ..not val4
            ..if val+dw, _1xx0x, _1xx1x
          _1xx0x:
            val+2*dw+dbit; yes
          _1xx1x:
            val+3*dw+dbit; yes

          yes:
            ..not val+dw
            ..not res
          no:
        }
    }


    //  Time Complexity: n^2(10@+20)
    // Space Complexity: n^2(11@+22)
    //   if b==0: goto end (do nothing)
    //   q = a/b  (signed division)
    //   r = a%b  (signed modulo - sign(r)==sign(a))
    // @NOTE: a,b are SIGNED numbers. If you want a division with unsigned ints, use the div macro.
    // @NOTE: this division implementation is WASTEFUL in space, yet saves running time, compared to div_loop.
    //
    // @NOTE: There is a better version: This one is slow, big, and doesn't error on b==0.
    //        Also it supports only one convention for the sign of the reminder.
    //        For a faster & better division see hex.div, hex.idiv.
    // q,a,b,r are bit[:n].
    def idiv n, a, b, q, r @ negative_a, negative_b, one_negative, neg_b_1, do_div, neg_b_2, neg_ans, end {
        .mov negative_a, a+dw*(n-1)
        .mov negative_b, b+dw*(n-1)
        .zero one_negative

        .if0 negative_a, neg_b_1
        .not one_negative
        .neg n, a
      neg_b_1:
        .if0 negative_b, do_div
        .not one_negative
        .neg n, b
      do_div:
        .div n, a, b, q, r

        .if0 negative_a, neg_b_2
        .neg n, a
        .neg n, r
      neg_b_2:
        .if0 negative_b, neg_ans
        .neg n, b
      neg_ans:
        .if0 one_negative, end
        .neg n, q
        ;end

      negative_a:
        .bit
      negative_b:
        .bit
      one_negative:
        .bit
      end:
    }


    //  Time Complexity: n^2(10@+20)
    // Space Complexity: n^2(11@+22)
    //   if b==0: goto end (do nothing)
    //   q = a/b  (unsigned division)
    //   r = a%b  (unsigned modulo)
    // @NOTE: a,b are UNSIGNED numbers. If you want a division with signed ints, use the idiv macro.
    // @NOTE: this division implementation is WASTEFUL in space, yet saves running time, compared to div_loop.
    //
    // @NOTE: There is a better version: This one is slow, big, and doesn't error on b==0.
    //        For a faster & better division see hex.div, hex.idiv.
    // q,a,b,r are bit[:n].
    def div n, a, b, q, r @ Q, R, end {
        .if0 n, b, end
        .zero 2*n, R
        .zero   n, Q

        rep(n, i) .div.div_step n,  a+(n-1-i)*dw,  b,  R+(n-1-i)*dw,  Q+(n-1-i)*dw

        .mov n, r, R
        .mov n, q, Q
        ;end

      R:
        .vec 2*n
      Q:
        .vec n
      end:
    }
    ns div {
        //  Time Complexity: n(10@+20)
        // Space Complexity: n(11@+22)
        //   R[0] ^= N
        //   if R[:n] >= D[:n]:
        //     R -= D
        //     not Q[0]
        //
        // R,D are bit[:n], while R,N are bits.
        def div_step n, N, D, R, Q @ do_sub, end {
            ..xor R, N
            ..cmp n, R, D, end, do_sub, do_sub
          do_sub:
            ..sub n, R, D
            ..not Q
          end:
        }
    }


    //  Time Complexity: n^2(18@+18)
    // Space Complexity: n(37@+58)
    //   if b==0: goto end (do nothing)
    //   q = a/b  (signed division)
    //   r = a%b  (signed modulo - sign(r)==sign(a))
    // @NOTE: a,b are SIGNED numbers. If you want a division with unsigned ints, use the div_loop macro.
    // @NOTE: this division implementation saves space, yet is slower, compared to div.
    //
    // @NOTE: There is a better version: This one is slow, big, and doesn't error on b==0.
    //        Also it supports only one convention for the sign of the reminder.
    //        For a faster & better division see hex.div, hex.idiv.
    // q,a,b,r are bit[:n].
    def idiv_loop n, a, b, q, r @ negative_a, negative_b, one_negative, neg_b_1, do_div, neg_b_2, neg_ans, end {
        .mov negative_a, a+dw*(n-1)
        .mov negative_b, b+dw*(n-1)
        .zero one_negative

        .if0 negative_a, neg_b_1
        .not one_negative
        .neg n, a
      neg_b_1:
        .if0 negative_b, do_div
        .not one_negative
        .neg n, b
      do_div:
        .div_loop n, a, b, q, r

        .if0 negative_a, neg_b_2
        .neg n, a
        .neg n, r
      neg_b_2:
        .if0 negative_b, neg_ans
        .neg n, b
      neg_ans:
        .if0 one_negative, end
        .neg n, q
        ;end

      negative_a:
        .bit
      negative_b:
        .bit
      one_negative:
        .bit
      end:
    }


    //  Time Complexity: n^2(18@+18)
    // Space Complexity: n(25@+22)
    //   if b==0: goto end (do nothing)
    //   q = a/b  (unsigned division)
    //   r = a%b  (unsigned modulo)
    // @NOTE: a,b are UNSIGNED numbers. If you want a division with signed ints, use the idiv_loop macro.
    // @NOTE: this division implementation saves space, yet is slower, compared to div.
    //
    // @NOTE: There is a better version: This one is slow, big, and doesn't error on b==0.
    //        For a faster division see hex.div, hex.idiv.
    // q,a,b,r are bit[:n].
    def div_loop n, a, b, q, r @ loop, do_sub, loop_end, after_loop, A, Q, R, i, end {
        .if0 n, b, end
        .zero n, R
        .zero n, Q
        .mov n, A, a
        .zero n, i
        .not i+(n-1)*dw

      loop:
        .if0 n, i, after_loop                //Comp: n(@+2)
        .shl n, R                            //Comp: n(2@-1)
        .xor R, A+(n-1)*dw
        .cmp n, R, b, loop_end, do_sub, do_sub   //Comp: n(2@+4)  (Space=n(3@+6))
      do_sub:
        .sub n, R, b                         //Comp: n(8@+16)
        .xor n, Q, i                         //Comp: n(@-1)
      loop_end:
        .shr n, i                            //Comp: n(2@-1)
        .shl n, A                            //Comp: n(2@-1)
        ;loop

      after_loop:
        .mov n, r, R
        .mov n, q, Q
        ;end

      A:
        .vec n
      R:
        .vec n
      Q:
        .vec n
      i:
        .vec n

      end:
    }
}

// ---------- Input:



ns bit {
    // Complexity: 2@-2
    //   input one bit into the bit-variable, 'dst'.
    // dst is an output parameter.
    def input_bit dst < stl.IO {
        .zero dst
        .xor dst, stl.IO
    }


    // Complexity: 16@-16
    //   input one byte into dst[:8] (lsb first)
    // dst is an output parameter.
    def input dst {
        rep(8, i) .input_bit dst+i*dw
    }


    // Complexity: n(16@-16)
    //   input n bytes into dst[:8n] (lsb first)
    // dst is an output parameter.
    def input n, dst {
        rep(n, i) .input dst+8*(n-1-i)*dw
    }
}

// ---------- Logical Macros


ns bit {
    // Complexity: @-1
    //   dst ^= src
    // dst,src are bits.
    def xor dst, src {
        .exact_xor dst + dbit, src
    }

    // Complexity: n(@-1)
    //   dst[:n] ^= src[:n]
    // dst,src are bit[:n].
    def xor n, dst, src {
        rep(n, i) .xor dst+dw*i, src+dw*i
    }

    // Complexity: @-1
    // note: pad 2 is needed, but pad 8 is used for wflips-padding optimization and for smaller wflips.
    //   dst(bit_address) ^= src
    // dst,src are bits.
    def exact_xor dst, src @ base_jump_label, cleanup {
        wflip src+w, base_jump_label, src
        pad 8
      base_jump_label:
        ;cleanup
        dst;
      cleanup:
        wflip src+w, base_jump_label
    }

    // Complexity: @
    // note: pad 2 is needed, but pad 8 is used for wflips-padding optimization and for smaller wflips.
    //   dst1(bit_address) ^= src
    //   dst2(bit_address) ^= src
    // dst1,dst2,src are bits.
    def double_exact_xor dst1, dst2, src @ base_jump_label, cleanup {
        wflip src+w, base_jump_label, src
        pad 8
      base_jump_label:
        ;cleanup
        dst1;
        dst2;
      cleanup:
        wflip src+w, base_jump_label
    }

    // Complexity: n@
    //   address(bit_address) ^= src
    //   var ^= src
    // var,src are bit[:n], address is an address.
    def address_and_variable_xor n, address, var, src {
        rep(n, i) .double_exact_xor address+i, var+dbit+i*dw, src+i*dw
    }

    // Complexity: @
    //   dst ^= src
    //   src = 0
    // dst,src are bits.
    def xor_zero dst, src {
        .double_exact_xor dst+dbit, src+dbit, src
    }

    // Complexity: n@
    //   dst[:n] ^= src[:n]
    //   src[:n] = 0
    // dst,src are bit[:n].
    def xor_zero n, dst, src {
        rep(n, i) .xor_zero dst+dw*i, src+dw*i
    }


    // Complexity: 2@+2
    //   dst |= src
    // dst,src are bits.
    def or dst, src @ end {
        .if0 src, end
        .one dst
      end:
    }

    // Complexity: n(2@+2)
    //   dst[:n] |= src[:n]
    // dst,src are bit[:n].
    def or n, dst, src {
        rep(n, i) .or dst+dw*i, src+dw*i
    }


    // Complexity: 2@+2
    //   dst &= src
    // dst,src are bits.
    def and dst, src @ end {
        .if1 src, end
        .zero dst
      end:
    }

    // Complexity: n(2@+2)
    //   dst[:n] &= src[:n]
    // dst,src are bit[:n].
    def and n, dst, src {
        rep(n, i) .and dst+dw*i, src+dw*i
    }


    // Complexity: 1
    //   dst ^= 1
    // dst is a bit.
    def not dst {
        dst + dbit;
    }

    // Complexity: n
    //   dst[:n] ^= (1<<n)-1
    // dst is bit[:n]
    def not n, dst {
        rep(n, i) .not dst+dw*i
    }

    // Complexity: 1
    //   dst(bit_address) ^= 1
    // dst is an address.
    def exact_not dst {
        dst;
    }
}

// ---------- Arithmetical Macros
// carry is both input and output


ns bit {
    // Unsafe for dst==carry (but there is no reason in calling it that way)
    // Complexity: 2@+6
    //   {carry:dst}++
    // carry,dst are bits.
    def inc1 dst, carry @ continue {
        .inc.inc1_with_carry0_jump dst, carry, continue
      continue:
    }

    ns inc {
        // Unsafe for dst==carry (but there is no reason in calling it that way)
        // If carry was 0, jump to carry0_jump.
        // Complexity: 2@+6
        //   {carry:dst}++
        // carry,dst are bits.
        def inc1_with_carry0_jump dst, carry, carry0_jump @ end {
            ..if0 carry, carry0_jump
            ..not dst
            ..if0 dst, end
            ..not carry
          end:
        }
    }

    //  Time Complexity: 5@+12 in average
    // Space Complexity: n(2@+6)
    //   x[:n]++
    // x is a bit[:n]
    def inc n, x @ carry, end {
        .one carry
        rep(n, i) .inc.inc1_with_carry0_jump x+i*dw, carry, end
        ;end
      carry:
        .bit
      end:
    }

    //  Time Complexity: 2n + 5@+12
    // Space Complexity: n(2@+6)
    //   x[:n]--
    // x is a bit[:n]
    def dec n, x {
        .not n, x
        .inc n, x
        .not n, x
    }

    //  Time Complexity: n + 5@+12
    // Space Complexity: n(2@+6)
    //   x[:n]--
    // x is a bit[:n]
    def neg n, x {
        .not n, x
        .inc n, x
    }


    // Unsafe for dst==carry (but there is no reason in calling it that way)
    // Complexity: 8@+14
    //   {carry:dst} += src
    // dst,src,carry are bits.
    def add1 dst, src, carry @ _src {
        .mov _src, src
        .inc1 dst, _src
        .inc1 dst, carry
        .or carry, _src
        stl.skip
      _src:
        .bit
    }

    // Complexity: n(8@+14)
    //   dst[:n] += src[:n]
    // dst,src are bit[:n]
    def add n, dst, src @ carry {
        .zero carry
        rep(n, i) .add1 dst+i*dw, src+i*dw, carry
        stl.skip
      carry:
        .bit
    }

    // Complexity: n(8@+16)
    //   dst[:n] -= src[:n]
    // dst,src are bit[:n]
    def sub n, dst, src @ carry {
        .not n, src
        .one carry
        rep(n, i) .add1 dst+i*dw, src+i*dw, carry
        .not n, src
        stl.skip
      carry:
        .bit
    }
}

// ---------- Memory Variables


ns bit {
    // Size Complexity: 1
    //
    // This is the basic variable in the FlipJump standard library - a bit (can contain only 0/1).
    // you can't place it as any other standard library macro, as "running" this line is undefined behavior.
    // The bit (and bit.vec) should be placed in a place that won't run.
    def bit value {
        ; value ? dw : 0
    }
    def bit {
        .bit 0
    }


    // Size Complexity: n
    // read the comment for the bit macro.
    def vec n, value {
        rep(n, i) .bit (value>>i)&1
