        .mov n, twice, x
        .shl n, 2, x
        .add n, x, twice
        ;end

      twice:
        .vec n
      end:
    }


    //  Time Complexity:  n^2(6@+2) + n*b(8@+14)    if b==n/2:  n^2(10@+9)
    // Space Complexity:  n(21@+11)
    //   dst[:n] *= src[:n]
