        .zero printed_flag
        rep(n/4, i) .print_hex_uint.print_digit x+(n/4-1-i)*4*dw, printed_flag

        .if1 printed_flag, end
        stl.output '0'
        ;end

      printed_flag:
        .bit
      end:
    }
