    // Space Complexity: w(1.13@+32) + 22@+255
    //   Like:  stack[++sp] = byte[:2]
    //   Pushes the given byte to the next cell in the stack. Increments sp.
    // byte is a hex[:2].
    def push_byte byte < hex.pointers.sp {
        .sp_inc
        .write_byte hex.pointers.sp, byte
    }

    //  Time Complexity: n(w(0.38@+ 3) + 13@+ 25)
    // Space Complexity: n(w(0.56@+16) + 11@+128)
    //   Like:  stack[sp+1:][:M] = hex[:n];  sp += n.
    //   Pushes the given hex[:n] to the next M cells in the stack. Increments sp by M.
    // M is (n+1)/2, which is because the function pushes the entire parameter as bytes.
    //
    // Note: This macro pushes bytes to the stack (2 hexs in one stack-cell).
    //
    // Note: The push/pop usage must be coordinated, and every push X must be untangled by a pop X (or a sp_sub (X+1)/2)
    //  For example: "push 3; push 3" can't be read with a "pop 6". That's because each "push 3" takes 2 stack cells,
    //               while the "pop 6" only pops out 3 stack cells (so there is another cell that needs to be popped.
    def push n, hex {
        rep(n/2, i) .push_byte hex+2*i*dw
        rep(n%2, i) .push_hex hex+(n-1)*dw
    }

    //  Time Complexity: w(0.75@+ 5) + 16@+ 36
    // Space Complexity: w(1.13@+32) + 12@+115
    //   Like:  hex = stack[sp--]
    //   Pops the current stack cell (only the least-significant-hex of it) into the the given hex. Decrements sp.
    // hex is only an output parameter.
    def pop_hex hex < hex.pointers.sp {
        .read_hex hex, hex.pointers.sp
        .sp_dec
    }

    //  Time Complexity: w(0.75@+ 5) + 18@+ 36
    // Space Complexity: w(1.13@+32) + 14@+139
    //   Like:  byte[:2] = stack[sp--]
    //   Pops the current stack cell into the the given byte. Decrements sp.
    // byte is hex[:2], and it's only an output parameter.
    def pop_byte byte < hex.pointers.sp {
        .read_byte byte, hex.pointers.sp
        .sp_dec
    }

    //  Time Complexity: n(w(0.38@+ 3) + 9@+18)
    // Space Complexity: n(w(0.56@+16) + 7@+70)
    //   Like:  sp -= M
    //          hex[:n] = stack[sp+1:][:M]
    //   Pops multiple stack cell into the the given hex[:n]. Decrements sp by M.
    // M is (n+1)/2, which is because the function pops all the parameters as bytes.
    //
    // Note: The pops assume that they were pushed as bytes to the stack (2 hexs in one stack-cell).
    //       So this macro pops bytes.
    //
    // Note: The push/pop usage must be coordinated, and every push X must be untangled by a pop X (or a sp_sub (X+1)/2)
    //  For example: "push 3; push 3" can't be read with a "pop 6". That's because each "push 3" takes 2 stack cells,
    //               while the "pop 6" only pops out 3 stack cells (so there is another cell that needs to be popped.
    // hex[:n] is only an output parameter.
    def pop n, hex {
        rep(n%2, i) .pop_hex hex+(n-1)*dw
        rep(n/2, i) .pop_byte hex+(n-n%2-2*(i+1))*dw
    }
}

// ---------- Write Pointers


ns hex {
    //  Time Complexity: w(0.75@+5)  + 11@+25
    // Space Complexity: w(0.75@+29) + 11@+112
    //   like:  *ptr = src
    // src is a hex. ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def write_hex ptr, src < hex.pointers.read_byte {
        .pointers.set_flip_and_jump_pointers ptr
        .pointers.read_byte_from_inners_ptrs
        .xor hex.pointers.read_byte, src
        .pointers.xor_hex_to_flip_ptr hex.pointers.read_byte
    }

    //  Time Complexity: w(0.75@+5)  + 15@+37
    // Space Complexity: w(0.75@+29) + 15@+176
    //   like:  *ptr = 0
    // ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def zero_ptr ptr < hex.pointers.read_byte {
        .pointers.set_flip_and_jump_pointers ptr
        .pointers.read_byte_from_inners_ptrs
        .pointers.xor_byte_to_flip_ptr hex.pointers.read_byte
    }

    //  Time Complexity: w(0.75@+5)  + 17@+37
    // Space Complexity: w(0.75@+29) + 17@+200
    //   like:  *ptr = src[:2]
    // src is a hex[:2]. ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def write_byte ptr, src < hex.pointers.read_byte {
        .pointers.set_flip_and_jump_pointers ptr
        .pointers.read_byte_from_inners_ptrs
        .xor 2, hex.pointers.read_byte, src
        .pointers.xor_byte_to_flip_ptr hex.pointers.read_byte
    }
}



// ---------- Multi Read Write Pointers


ns hex {
    //  Time Complexity: w(0.75@+5)  + 20@+39
    // Space Complexity: w(1.13@+32) + 16@+167
    //   like:  *ptr = src
    //          ptr++
    // src is a hex. ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def write_hex_and_inc ptr, src {
        .write_hex ptr, src
        .ptr_inc ptr
    }

    //  Time Complexity:  n(w(0.75@+5)  + 20@+39)
    // Space Complexity:  n(w(1.13@+32) + 16@+167)
    //   like:  *ptr[:n] = src[:n]
    // src is a hex[:n]. ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def write_hex n, ptr, src {
        rep(n, i) .write_hex_and_inc ptr, src + i*dw
        .ptr_sub ptr, n
    }

    //  Time Complexity: w(0.75@+5)  + 26@+51
    // Space Complexity: w(1.13@+32) + 22@+255
    //   like:  *ptr = src[:2]
    //          ptr++
    // src is a hex[:2]. ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def write_byte_and_inc ptr, src {
        .write_byte ptr, src
        .ptr_inc ptr
    }

    //  Time Complexity: n(w(0.75@+5)  + 26@+51)
    // Space Complexity: n(w(1.13@+32) + 22@+255)
    //   like:  *ptr[:n] = src[:2n]
    // src is a hex[:2n]. ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def write_byte n, ptr, src {
        rep(n, i) .write_byte_and_inc ptr, src + i*2*dw
        .ptr_sub ptr, n
    }
}

ns hex {
    //  Time Complexity: w(0.75@+ 5) + 6@+13
    // Space Complexity: w(0.75@+29) + 6@+36
    //   like:  dst ^= *ptr
    // dst is a hex. ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def xor_hex_from_ptr dst, ptr < hex.pointers.read_byte {
        .pointers.set_flip_and_jump_pointers ptr
        .pointers.read_byte_from_inners_ptrs
        .xor dst, hex.pointers.read_byte
    }

    //  Time Complexity: w(0.75@+ 5) + 7@+13
    // Space Complexity: w(0.75@+29) + 7@+48
    //   like:  dst[:2] ^= *ptr
    // dst is a hex[2:]. ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def xor_byte_from_ptr dst, ptr < hex.pointers.read_byte {
        .pointers.set_flip_and_jump_pointers ptr
        .pointers.read_byte_from_inners_ptrs
        .xor 2, dst, hex.pointers.read_byte
    }

    ns pointers {
        //  Time Complexity: 5@+13
        // Space Complexity: 5@+24
        //   use after:  hex.pointers.set_flip_and_jump_pointers ptr
        //   does:       hex.pointers.read_byte[:2] = *ptr
        //
        // ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
        def read_byte_from_inners_ptrs @ read_ptr_and_flip_back, cleanup \
                < hex.pointers.ret_after_read_byte, hex.pointers.read_byte, hex.pointers.to_jump, hex.pointers.to_flip {
            // 1.  setup:
            //       zero read_byte.
            //       to_flip   = ptr + dbit+8.
            //       to_jump+w = ptr.
            hex.zero 2, hex.pointers.read_byte
            wflip hex.pointers.to_flip, dbit+8

            // 2.  *(ptr+w)^=256, so that now *(ptr+w) == 256 + original_value.
            wflip hex.pointers.to_flip+w, read_ptr_and_flip_back, hex.pointers.to_flip

            pad 4
          read_ptr_and_flip_back:
            // 3.  Jump to *(ptr+w). It will xor the pointed original_value byte into hex.pointers.read_byte.
            // 4.  Then jump to hex.pointers.to_flip to make *(ptr+w)==original_value back again.
            // 5.  Then return to cleanup.
            wflip hex.pointers.to_flip+w, read_ptr_and_flip_back^cleanup
            wflip hex.pointers.ret_after_read_byte+w, hex.pointers.to_flip, hex.pointers.to_jump

          cleanup:
            // 6.  to_flip = ptr, clean jump-back addresses.
            wflip hex.pointers.ret_after_read_byte+w, hex.pointers.to_flip
            wflip hex.pointers.to_flip, dbit+8
            wflip hex.pointers.to_flip+w, cleanup
        }
    }
}

ns hex {
    //  Time Complexity: w(0.5@+2)  + @
    // Space Complexity: w(0.5@+14) + @
    //   like:  *ptr;
    //   Flip the address the pointer points to.
    // ptr is a hex[:w/4] that holds an address.
    def ptr_flip ptr @ cleanup < hex.pointers.to_flip {
        wflip hex.pointers.to_flip+w, cleanup

        .pointers.set_flip_pointer ptr
        ;hex.pointers.to_flip

        pad 4
      cleanup:
        wflip hex.pointers.to_flip+w, cleanup
    }


    //  Time Complexity: w(0.5@+2)  + @+6
    // Space Complexity: w(0.5@+14) + @+6
    // The stl.comp_flip_if executes in ~##w, which should be much less than @/2 operations.
    //   like:  (*ptr)+dbit;
    //   Flip the address dbit-ahead of what the pointer points to.
    // ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def ptr_flip_dbit ptr < .pointers.to_flip {
        wflip .pointers.to_flip, dbit
        .ptr_flip ptr
        wflip .pointers.to_flip, dbit
    }


    //  Time Complexity: w(0.5@+2)  + 5@+12
    // Space Complexity: w(0.5@+14) + 5@+76
    //   like:  hex.xor *ptr, hex
    // ptr is a hex[:w/4] that holds an address, which we assume is an hex-variable, which is dw-aligned.
    def xor_hex_to_ptr ptr, hex {
        .pointers.set_flip_pointer ptr
        .pointers.xor_hex_to_flip_ptr hex
    }

    //  Time Complexity: w(0.5@+2)  + 10@+24
    // Space Complexity: w(0.5@+14) + 10@+152
    //   like:  hex.xor *ptr, hex[:2]
    // ptr is a hex[:w/4] that holds an address, which we assume is an hex-variable, which is dw-aligned.
    def xor_byte_to_ptr ptr, hex {
        .pointers.set_flip_pointer ptr
        .pointers.xor_byte_to_flip_ptr hex
    }

    //  Time Complexity: n(w(0.5@+2)  + 14@+26)
    // Space Complexity: n(w(0.9@+17) + 10@+131)
    //   like:  hex.xor *ptr[:n], hex[:n]
    // ptr is a hex[:w/4] that holds an address, which we assume is an hex-variable, which is dw-aligned.
    def xor_hex_to_ptr n, ptr, hex {
        rep(n, i) .pointers.xor_hex_to_ptr_and_inc ptr, hex + i*dw
        .ptr_sub ptr, n
    }

    //  Time Complexity: n(w(0.5@+2)  + 19@+38)
    // Space Complexity: n(w(0.9@+17) + 15@+207)
    //   like:  hex.xor *ptr[:n], hex[:2n]
    // ptr is a hex[:w/4] that holds an address, which we assume is an hex-variable, which is dw-aligned.
    def xor_byte_to_ptr n, ptr, hex {
        rep(n, i) .pointers.xor_byte_to_ptr_and_inc ptr, hex + i*2*dw
        .ptr_sub ptr, n
    }

    ns pointers {
        //  Time Complexity: w(0.5@+2)  + 14@+26
        // Space Complexity: w(0.9@+17) + 10@+131
        //   like:  hex.xor *ptr, hex
        //          ptr += dw
        // ptr is a hex[:w/4] that holds an address, which we assume is an hex-variable, which is dw-aligned.
        def xor_hex_to_ptr_and_inc ptr, hex {
            ..xor_hex_to_ptr ptr, hex
            ..ptr_inc ptr
        }

        //  Time Complexity: w(0.5@+2)  + 19@+38
        // Space Complexity: w(0.9@+17) + 15@+207
        //   like:  hex.xor *ptr, hex[:2]
        //          ptr += dw
        // ptr is a hex[:w/4] that holds an address, which we assume is an hex-variable, which is dw-aligned.
        def xor_byte_to_ptr_and_inc ptr, hex {
            ..xor_byte_to_ptr ptr, hex
            ..ptr_inc ptr
        }


        //  Time Complexity: 5@+12
        // Space Complexity: 5@+76
        //   xors (the parameter hex) to the hex pointed by the memory-word hex.pointers.to_flip.
        //   use after:  .pointers.set_flip_pointer ptr
        //   does:       .xor *ptr, hex    (as it uses the address in to_flip)
        // It assumes that the value in the memory-word to_flip is a dw-aligned address to an hex-variable.
        def xor_hex_to_flip_ptr hex {
            .xor_hex_to_flip_ptr hex, 0
        }

        //  Time Complexity: 10@+24
        // Space Complexity: 10@+152
        //   xors (the byte hex[2:]) to the byte pointed by the memory-word hex.pointers.to_flip.
        //   use after:  .pointers.set_flip_pointer ptr
        //   does:       .xor *ptr, hex[:2]    (as it uses the address in to_flip)
        // It assumes that the value in the memory-word to_flip is a dw-aligned address to an hex-variable.
        def xor_byte_to_flip_ptr hex {
            rep(2, i) .xor_hex_to_flip_ptr hex+i*dw, 4*i
        }

        //  Time Complexity: 5@+12
        // Space Complexity: 5@+76
        //   xors (the parameter hex, shifted left by bit_shift) to the hex/byte pointed by the memory-word hex.pointers.to_flip.
        //   use after:  .pointers.set_flip_pointer ptr
        //   does:       .xor *ptr, hex<<bit_shift    (as it uses the address in to_flip)
        // It assumes that the value in the memory-word to_flip is a dw-aligned address to an hex-variable.
        // bit_shift is a constant that's assumed to be divisible by 4.
        def xor_hex_to_flip_ptr hex, bit_shift @ prepare_flip_bit0, prepare_flip_bit1, prepare_flip_bit2, prepare_flip_bit3, \
                after_flip_bit0, after_flip_bit1, after_flip_bit2, after_flip_bit3,  cleanup  < hex.pointers.to_flip {
            wflip hex.pointers.to_flip+w, after_flip_bit0, prepare_flip_bit0

          prepare_flip_bit0:
            wflip hex.pointers.to_flip, dbit+0+bit_shift
            hex.if_flags hex, 0xAAAA, after_flip_bit0, hex.pointers.to_flip
          prepare_flip_bit1:
            wflip hex.pointers.to_flip, (dbit+0+bit_shift)^(dbit+1+bit_shift)
            hex.if_flags hex, 0xCCCC, after_flip_bit1, hex.pointers.to_flip
          prepare_flip_bit3:
            wflip hex.pointers.to_flip, (dbit+1+bit_shift)^(dbit+3+bit_shift)
            hex.if_flags hex, 0xFF00, after_flip_bit3, hex.pointers.to_flip
          prepare_flip_bit2:
            wflip hex.pointers.to_flip, (dbit+3+bit_shift)^(dbit+2+bit_shift)
            hex.if_flags hex, 0xF0F0, after_flip_bit2, hex.pointers.to_flip

            pad 4
          after_flip_bit0:
            hex.pointers.to_flip+dbit+0;prepare_flip_bit1
          after_flip_bit1:
            hex.pointers.to_flip+dbit+1;prepare_flip_bit3
          after_flip_bit2:
            wflip hex.pointers.to_flip, dbit+2+bit_shift, cleanup
          after_flip_bit3:
            hex.pointers.to_flip+dbit+0;prepare_flip_bit2

          cleanup:
            wflip hex.pointers.to_flip+w, after_flip_bit2
        }
    }

    //  Time Complexity: w(1.5@+5)
    // Space Complexity: w(1.5@+17)
    //   like:  wflip *ptr, value
    // ptr is a hex[:w/4] that holds an address, which we assume is w-aligned.
    def ptr_wflip ptr, value {
        .pointers.set_flip_pointer ptr
        rep(w, i) .pointers.advance_by_one_and_flip__ptr_wflip (#(i^((i+1)%w))), (value>>i)&1
    }
    ns pointers {
        // Advances *to_flip by 1 (which takes n flips, from bit0 to bit1, bit2,...).
        // If do_flip (value) isn't 0 - than make a flip, like:  to_flip;advance.
        def advance_by_one_and_flip__ptr_wflip n, do_flip @ cleanup, advance < hex.pointers.to_flip {
            stl.comp_if0 do_flip, advance
            wflip hex.pointers.to_flip+w, cleanup, hex.pointers.to_flip
          cleanup:
            wflip hex.pointers.to_flip+w, cleanup, advance

            pad 4
          advance:
            rep(n, i) bit.exact_not hex.pointers.to_flip+i
        }
    }

    //  Time Complexity: w(1.5@+5)
    // Space Complexity: w(1.5@+17)
    //   like:  wflip (*ptr)+w, value
    // ptr is a hex[:w/4] that holds an address, which we assume is dw-aligned.
    def ptr_wflip_2nd_word ptr, value {
        ptr+dbit + ((#w-1)/4)*dw + (#w-1)%4;
        hex.ptr_wflip ptr, value
        ptr+dbit + ((#w-1)/4)*dw + (#w-1)%4;
    }
}

// ---------- Logical Shifts:


ns hex {
    //  Time Complexity: n(@+1)
    // Space Complexity: n(@+28)
    //   dst[:n] <<= 1
    def shl_bit n, dst {
        .shifts.shl_bit_once dst+(n-1)*dw, 0
        rep(n-1, i) .shifts.shl_bit_once dst+(n-2-i)*dw, dst+(n-1-i)*dw
    }


    //  Time Complexity: n(@+1)
    // Space Complexity: n(@+28)
    //   dst[:n] >>= 1
    def shr_bit n, dst {
        .shifts.shr_bit_once dst, 0
        rep(n-1, i) .shifts.shr_bit_once dst+(i+1)*dw, dst+i*dw
    }


    //  Time Complexity: n(@+4)
    // Space Complexity: n(@+28)
    //   dst[:n] <<= 4
    def shl_hex n, dst {
        .shl_hex n, 1, dst
    }

    //  Time Complexity: n(@+4)
    // Space Complexity: n(@+28)
    //   dst[:n] <<= 4*times
    def shl_hex n, times, dst @ end {
        stl.comp_if0 times, end
        .zero times, dst+(n-times)*dw
        rep(n-times, i) .xor_zero dst+(n-1-i)*dw, dst+(n-1-times-i)*dw
      end:
    }


    //  Time Complexity: n(@+4)
    // Space Complexity: n(@+28)
    //   dst[:n] >>= 4
    def shr_hex n, dst {
        .shr_hex n, 1, dst
    }

    //  Time Complexity: n(@+4)
    // Space Complexity: n(@+28)
    //   dst[:n] >>= 4*times
    def shr_hex n, times, dst @ end {
        stl.comp_if0 times, end
        .zero times, dst
        rep(n-times, i) .xor_zero dst+i*dw, dst+(i+times)*dw
      end:
    }
}


ns hex {
    ns shifts {
        //  Time Complexity: @+1
        // Space Complexity: @+28
        //    {next(1bit),dst(1hex)} = dst << 1
        //
        // next is the bit-address of the next msb, dst is a hex.
        // @note, this should be called in reverse order (so that the "next" is already shifted).
        def shl_bit_once dst, next @ switch, xor_by, end {
            wflip dst+w, switch, dst

            pad 16
          switch:
            rep(16, i) stl.fj    i&8 ? next+dbit+0 : 0,  xor_by+(i^((i<<1)&0xf))*dw
          xor_by:
            ..tables.clean_table_entry__table 16, dst, end

          end:
            wflip dst+w, switch
        }


        //  Time Complexity: @+1
        // Space Complexity: @+28
        //    {next(1bit),dst(1hex)} = dst >> 1
        //
        // next is the bit-address of the next msb, dst is a hex.
        // @note, this should be called in a regular order (so that the "next" is already shifted).
        def shr_bit_once dst, next @ switch, xor_by, end {
            wflip dst+w, switch, dst

            pad 16
          switch:
            rep(16, i) stl.fj    i&1 ? next+dbit+3 : 0,  xor_by+(i^((i>>1)&0xf))*dw
          xor_by:
            ..tables.clean_table_entry__table 16, dst, end

          end:
            wflip dst+w, switch
        }
    }
}

// ---------- Init The Truth Tables:


ns hex {
    // Space Complexity: 6500   (6464+@)
    //                   It is 50/100KB (for w=32/64 bits)
    //                   It is 5KB in --version 3 (for both w=32/64 bits)
    // This macro initializes all truth tables for the hex-macros.
    // Use this macro exactly once, and don't use it alongside any other hex.*.init macros, as it will declare those twice.
    // @output-param ret: The return address. Jumps to it after finishing going through a table.
    // @output-param res: The result of the table calculation is written here.
    def init {
        .tables.init_all
    }

    ns tables {
        def init_shared > ret, res {
          ret: ;0
          res: ..hex
        }

        // This is the inner-macro of hex.init, and it's identical to it. see hex.init documentation.
        def init_all @ end {
            ;end
          .init_shared
          ..or.init     //  595
          ..and.init    //  595
          ..mul.init    // 1620+@
          ..cmp.init    //  514
          ..add.init    // 1570
          ..sub.init    // 1570
          end:
        }

        // @Assumes: n must be a power of 2, and it must be (1<<n)-padded.
        // A table. When jumping to entry d - it xors d into dst, and jumps to ret.
        //
        //  Time Complexity: log(n) / 2     (an overage over all entries, of jumping to an entry in this table)
        // Space Complexity: n
        //
        // n is a size-constant, dst/ret are hexes.
        def clean_table_entry__table n, dst, ret @ clean {
          clean:
            rep(n, d) stl.fj \
                d==0?0: (dst+dbit+(#d)-1), \
                (d==((1<<(#d))>>1)) ? ret : clean+(d^((1<<(#d))>>1))*dw
        }

        // A table. When jumping to entry d - it xors d into dst, and jumps to hex.tables.ret
        //
        //  Time Complexity: 4
        // Space Complexity: 256
        //
        // dst is a hex.
        def clean_table_entry__table dst < .ret {
            .clean_table_entry__table 256, dst, .ret
        }

        // The macro assumes that jumper_to_table is a fj-op that jumps to a 256-padded table.
        //   This macro is used as a jumper to a table that sets hex.tables.res to some (calc(dst, src) ^ dst), and jumps back.
        //
        //  Time Complexity: 4@+4
        // Space Complexity: 4@+52
        //
        // It jumps to the table, at entry (src<<4 | dst).
        // At last, it xors the value of hex.tables.res into dst.
        //
        // both dst,src are hexes, and jumper_to_table is an address.
        def jump_to_table_entry dst, src, jumper_to_table @ return < .ret, .res {
            ..xor jumper_to_table  , dst
            ..xor jumper_to_table+4, src
            wflip .ret+w, return, jumper_to_table
          return:
            wflip .ret+w ,return
            ..xor_zero dst, .res
        }
    }
}

// ---------- Init


ns stl {
    // NOTE: must be placed just after the startup, so that the read_ptr_byte_table will be in address 256.
    // Complexity: 2.5w+263
    def ptr_init {
        hex.pointers.ptr_init
        bit.pointers.ptr_init
    }

    // Space Complexity: n+w/4
    //   Initializes a stack of size n (maximal capacity of n hexes / return-addresses).
    // n is the size of the stack.
    def stack_init n {
        hex.pointers.stack_init n
    }
}



// ---------- Functions


// @requires the stack_init.
ns stl {
    //  Time Complexity: ~2.5w@  (exact: w(2.25@+10)   + 24@+51)
    // Space Complexity: <3w@    (exact: w(2.625@+49) + 20@+231)
    //   Saves the return address to the stack and jumps to the given "address".
    //   When returned, it removes the return-address from the stack.
    //
    // note: the pop_ret_address is for the future return (counts as space, but not time, complexity).
    // @requires the stack_init.
    def call address @ return_label {
        hex.push_ret_address return_label
        ;address

        pad 2
      return_label:
        hex.pop_ret_address return_label
    }

    //  Time Complexity: <3w@  (exact: w(2.25@+10)  + 37@+57)
    // Space Complexity: <3w@  (exact: w(2.625@+49) + 43@+251)
    //   Saves the return address to the stack and jumps to the given "address".
    //   When returned, it removes the return-address from the stack, and pops "params_stack_length" cells from the stack.
    //
    // note: the pop_ret_address is for the future return (counts as space, but not time, complexity).
    // @requires the stack_init.
    def call address, params_stack_length @ return_label {
        hex.push_ret_address return_label
        ;address

        pad 2
      return_label:
        hex.pop_ret_address return_label
        hex.sp_sub params_stack_length
    }


    //  Time Complexity: w(2@+7)      + 9@+23
    // Space Complexity: w(2.375@+34) + 5@+67
    //   Returns to the calling function (gets the return-address from the top of the stack).
    //
    // note: jumps to the last-call's pop_ret_address (which this macro counts as time, but not space, complexity).
    // @requires the stack_init.
    def return < hex.pointers.sp {
        hex.ptr_jump hex.pointers.sp
    }


    //  Time Complexity: n(2@)
    // Space Complexity: n(2@+24)
    // (Unsafe if dst overlaps with hex.pointers.sp).
    //   dst[:w/4] = sp
    // @requires the stack_init.
    def get_sp dst < hex.pointers.sp {
        hex.mov w/4, dst, hex.pointers.sp
    }
}



// ---------- Fast Call


ns stl {
    // Complexity: @-1
    //   Jumps to label, and saves the return address in the given "ret_reg" variable.
    def fcall label, ret_reg @ ret {
        wflip ret_reg+w, ret, label
        pad 2
      ret:
        wflip ret_reg+w, ret
    }

    // Complexity: 1
    //   Return into the address written in the "ret_reg" variable.
    def fret ret_reg {
        ;ret_reg
    }
}

// w = ??       // memory and operands width. Is defined at compile time.
dw   = 2 * w    // double word size
dbit = w + #w   // the bit-distance from the variable's start, to the bit/hex value (w + dw-width)


// More info about the FlipJump input / output in: https://esolangs.org/wiki/FlipJump#Input_/_Output


ns stl {
    // Complexity: 2
    // startup Macro - Should be the first piece of code in your program.
    //                 Inits the IO variable, and jumps to the next instruction.
    def startup @ code_start {
        stl.startup code_start
      code_start:
    }

    // Complexity: 2
    // startup Macro - Should be the first piece of code in your program.
    //                 Inits the IO variable, and jumps to the given code start.
    // @output-param IO: the address of the opcode that's reserved for Input/Output. More info in https://esolangs.org/wiki/FlipJump#Input_/_Output
    def startup code_start > IO {
        ;code_start    // 0w;1w : first code to run
      IO:
        ;0             // 2w;3w : sets the io_handler to address 0 (good for a future wflip)
    }

    // Complexity: 2.5w+265
    // startup Macro - Should be the first piece of code in your program.
    //                 Inits the IO variable, and the pointers globals.
    //                 Jumps to the next instruction.
    def startup_and_init_pointers @ code_start {
        stl.startup_and_init_pointers code_start
      code_start:
    }

    // Complexity: 2.5w+265
    // startup Macro - Should be the first piece of code in your program.
    //                 Inits the IO variable, and the pointers globals.
    //                 Jumps to the given code_start.
    def startup_and_init_pointers code_start {
        stl.startup code_start
        // NOTE: must be placed just after the startup, so that the read_ptr_byte_table will be in address 256.
        stl.ptr_init
    }

    // Complexity: ~7000  (7026 for w=64, 6894 for w=16)
    // startup Macro - Should be the first piece of code in your program.
    //                 Initialize anything needed for the standard library.
    def startup_and_init_all {
        .startup_and_init_all 100
    }

    // Complexity: 6725 + 2.75w+@ + n
    // startup Macro - Should be the first piece of code in your program.
    //                 Initialize anything needed for the standard library.
    // stack_bit_size is the size of the global-stack (will hold this number of bits / return-addresses).
    def startup_and_init_all stack_bit_size @ code_start {
        .startup_and_init_all code_start, stack_bit_size
      code_start:
    }

    // Complexity: 6725 + 2.75w+@ + n
    // startup Macro - Should be the first piece of code in your program.
    //                 Initialize anything needed for the standard library.
    // stack_bit_size is the size of the global-stack (will hold this number of hexes / return-addresses).
    def startup_and_init_all code_start, stack_bit_size {
        stl.startup_and_init_pointers code_start
        hex.init
        stl.stack_init stack_bit_size
    }



    // ---------- Basic Functionality


    // Complexity: 1
    //   macro for 1 flip-jump op
    def fj f, j {
        f;j
    }


    // Complexity: @
    //   macro for 1 wflip op
    def wflip_macro dst, val {
        wflip dst, val
    }


    // Complexity: @
    //   macro for 1 wflip op (with jump)
    def wflip_macro dst, val, jmp_addr {
        wflip dst, val, jmp_addr
    }



    // ---------- Compilation Time Comparisons:
    // Complexity: 1


    // if expression is 0 (compilation time), jump to l0. else jump to l1
    def comp_if expr, l0, l1 {
        ; expr ? l1 : l0
    }

    // if expression is 0 (compilation time), jump to l0. else continue
    def comp_if0 expr, l0 @ continue {
        .comp_if expr, l0, continue
      continue:
    }

    // if expression is not 0 (compilation time), jump to l1. else continue
    def comp_if1 expr, l1 @ continue {
        .comp_if expr, continue, l1
      continue:
    }


    // if expr != 0 (compilation time), flip the given bit.
    //
    // expr is a constant, and bit is a general bit-address.
    def comp_flip_if bit, expr {
        (expr ? bit : 0);
    }



    // ---------- Unconditional Jumps
    // Complexity: 1


    // skip the next flip-jump op
    def skip {
        ;$ + dw
    }


    // finish (loop to self)
    def loop {
        ;$ - dw
    }



    // ---------- Output constants:


    // Complexity: 1
    // bit is a constant. 0 will output o, anything else will output 1.
    def output_bit bit < .IO {
        .IO + (bit ? 1 : 0);
    }

    // Complexity: 8
    // ascii is a constant. The macro outputs the byte (ascii & 0xff)
    def output_char ascii {
        rep(8, i) .output_bit (ascii>>i)&1
    }

    // Complexity: 8 * string_length
    // str is a constant. The macro outputs the bytes of it (from lsB to msB) until it becomes all zeros.
    def output str {
        rep(((#str)+7)>>3, i) .output_char (str>>(8*i))&0xff
    }
}
